To implement a dictionary using a binary search tree (BST) in C++, we need to define a `Node` structure to represent each entry in the BST, and then create a `Dictionary` class that manages the BST. Below is a well-structured C++ program that fulfills your requirements:

```cpp
#include <iostream>
#include <string>
#include <map>
#include <vector>
#include <iomanip>
#include <sstream>

using namespace std;

// Node structure for the BST
struct Node {
    string word;
    string definition;
    Node* left;
    Node* right;

    Node(string w, string d) : word(w), definition(d), left(nullptr), right(nullptr) {}
};

// BST class for the dictionary
class Dictionary {
private:
    Node* root;

    // Helper function to insert a word into the BST
    void insert(Node* &node, string word, string definition) {
        if (node == nullptr) {
            node = new Node(word, definition);
            return;
        }

        if (word < node->word) {
            insert(node->left, word, definition);
        } else if (word > node->word) {
            insert(node->right, word, definition);
        }
    }

    // Helper function to search for a word in the BST
    Node* search(Node* node, string word) {
        if (node == nullptr) return nullptr;
        if (node->word == word) return node;
        if (word < node->word) return search(node->left, word);
        else return search(node->right, word);
    }

    // Helper function to delete a word from the BST
    void deleteNode(Node* &node, string word) {
        if (node == nullptr) return;

        if (word < node->word) {
            deleteNode(node->left, word);
        } else if (word > node->word) {
            deleteNode(node->right, word);
        } else {
            // Node found, delete it
            if (node->left == nullptr) {
                Node* temp = node->right;
                delete node;
                node = temp;
            } else if (node->right == nullptr) {
                Node* temp = node->left;
                delete node;
                node = temp;
            } else {
                // Find the in-order successor
                Node* temp = node->right;
                while (temp->left != nullptr) {
                    temp = temp->left;
                }

                // Copy the in-order successor's value
                node->word = temp->word;
                node->definition = temp->definition;

                // Delete the in-order successor
                deleteNode(node->right, temp->word);
            }
        }
    }

    // Helper function to print the BST in-order
    void inOrderTraversal(Node* node) {
        if (node != nullptr) {
            inOrderTraversal(node->left);
            cout << leftPad(node->word, 15) << " | " << leftPad(node->definition, 20) << endl;
            inOrderTraversal(node->right);
        }
    }

    // Helper function to print the BST in a formatted way
    void printDictionary() {
        inOrderTraversal(root);
    }

    // Helper function to format strings with padding
    string leftPad(string s, int width) {
        string padded = s;
        while (padded.length() < width) {
            padded += ' ';
        }
        return padded;
    }
};

// Main function to interact with the user
int main() {
    Dictionary dict;

    string inputWord, inputDefinition;
    bool exit = false;

    cout << "Welcome to the Dictionary using Binary Search Tree!\n";
    cout << "Enter a word and its definition (type 'exit' to quit):\n";

    while (!exit) {
        cout << "> ";
        getline(cin, inputWord);
        if (inputWord == "exit") {
            exit = true;
            continue;
        }

        cout << "Enter the definition: ";
        getline(cin, inputDefinition);

        // Insert into the BST
        dict.insert(dict.root, inputWord, inputDefinition);

        // Print the dictionary
        cout << "\nDictionary Contents:\n";
        dict.printDictionary();
    }

    cout << "\nGoodbye! Thanks for using the Dictionary!\n";

    return 0;
}
```

### Features Implemented:
1. **Insertion**: Users can add words and their definitions to the BST.
2. **Search**: Users can look up a word and retrieve its definition.
3. **Deletion**: Users can remove a word and its definition from the BST.
4. **Display**: The dictionary is printed in a formatted way, with words and definitions aligned properly.
5. **User Interface**: The program asks for input and provides appropriate feedback.

### Notes:
- The `leftPad` function ensures that words and definitions are aligned with consistent spacing.
- The `inOrderTraversal` function prints the dictionary in in-order traversal (left, root, right), which is suitable for BSTs.
- The program uses a `Dictionary` class that encapsulates the BST logic.

