# Perl Script: Haversine Distance Calculator

This Perl script calculates the distance between two locations using the Haversine formula. It accepts latitude and longitude inputs for two locations, calculates the distance in kilometers or miles, and includes error handling and documentation.

---

## Script: `haversine.pl`

```perl
#!/usr/bin/perl
use strict;
use warnings;
use Getopt::Long;
use JSON;

# Script: haversine.pl
# Purpose: Calculate the distance between two locations using the Haversine formula.
# Author: [Your Name]
# Date: [Date]

# Script documentation
# ==========
# This script calculates the distance between two points on the Earth's surface
# using the Haversine formula. It supports both kilometers and miles as output units.
# It includes error handling for invalid inputs and unavailability of location data.

# Configuration
my $km = 1;  # Default unit: kilometers
my $mi = 0;  # Default unit: miles

# Parse command-line options
GetOptions(
    'km' => \$km,
    'mi' => \$mi,
    'help' => \&help,
    'version' => \&version,
) or die "Usage: $0 [options]\n";

# Help message
sub help {
    print <<EOF;
Usage: $0 [options]
Options:
  -km   Output distance in kilometers
  -mi   Output distance in miles
  -h    Show this help message
  -v    Show version information
EOF
    exit;
}

# Version information
sub version {
    print <<EOF;
haversine.pl v1.0
This script calculates the distance between two locations using the Haversine formula.
EOF
    exit;
}

# Main function
sub main {
    # Check for required arguments
    if (@ARGV < 2) {
        die "Usage: $0 <lat1> <lon1> <lat2> <lon2>\n";
    }

    # Parse input arguments
    my ($lat1, $lon1, $lat2, $lon2) = @ARGV;

    # Validate input
    if (!($lat1 =~ /^-?\d+(\.\d+)?$/ || $lat1 =~ /^-?\d+\.?\d+$/) ||
        !($lon1 =~ /^-?\d+(\.\d+)?$/ || $lon1 =~ /^-?\d+\.?\d+$/) ||
        !($lat2 =~ /^-?\d+(\.\d+)?$/ || $lat2 =~ /^-?\d+\.?\d+$/) ||
        !($lon2 =~ /^-?\d+(\.\d+)?$/ || $lon2 =~ /^-?\d+\.?\d+$/)) {
        die "Invalid input: Latitude and longitude must be numeric.\n";
    }

    # Convert degrees to radians
    my $lat1_rad = deg2rad($lat1);
    my $lon1_rad = deg2rad($lon1);
    my $lat2_rad = deg2rad($lat2);
    my $lon2_rad = deg2rad($lon2);

    # Haversine formula
    my $a = sin($lat1_rad - $lat2_rad) ** 2 +
           cos($lat1_rad) * cos($lat2_rad) * sin($lat1_rad - $lon1_rad) ** 2;
    my $c = 2 * atan2(sqrt($a), sqrt(1 - $a));
    my $distance = $c * Earth_radius;

    # Convert distance to the desired unit
    my $distance_km = $distance * $km;
    my $distance_mi = $distance_km * 0.621371;

    # Output results
    print "Distance between $lat1, $lon1 and $lat2, $lon2 is: \n";

    if ($km == 1) {
        print "$distance_km kilometers\n";
    } else {
        print "$distance_km kilometers or $distance_mi miles\n";
    }

    print "Location 1: $lat1, $lon1\n";
    print "Location 2: $lat2, $lon2\n";
}

# Helper function to convert degrees to radians
sub deg2rad {
    return ( $_[0] * pi() ) / 180;
}

# Earth radius in kilometers
my $Earth_radius = 6371;

# Run the script
main();
```

