Certainly! Below is a Swift implementation of a Binary Search Tree (BST) with insertion, deletion, and traversal functions. The code includes comments to explain the logic and ensures the tree maintains the BST properties.

```swift
import Foundation

// Define a Node structure for the BST
struct Node {
    var value: Int
    var left: Node?
    var right: Node?

    init(_ value: Int) {
        self.value = value
        self.left = nil
        self.right = nil
    }
}

// Define the BST class
class BinarySearchTree {
    var root: Node?

    // Insert a new value into the BST
    func insert(_ value: Int) {
        root = insertNode(root, value)
    }

    // Helper function to insert a node into the BST
    private func insertNode(_ node: Node?, _ value: Int) -> Node? {
        if node == nil {
            return Node(value)
        }

        if value < node!.value {
            node!.left = insertNode(node!.left, value)
        } else {
            node!.right = insertNode(node!.right, value)
        }

        return node!
    }

    // Delete a value from the BST
    func delete(_ value: Int) {
        root = deleteNode(root, value)
    }

    // Helper function to delete a node from the BST
    private func deleteNode(_ node: Node?, _ value: Int) -> Node? {
        if node == nil {
            return nil
        }

        if value < node!.value {
            node!.left = deleteNode(node!.left, value)
        } else if value > node!.value {
            node!.right = deleteNode(node!.right, value)
        } else {
            // Node found, delete it
            if node!.left == nil {
                return node!.right
            } else if node!.right == nil {
                return node!.left
            } else {
                // Node has two children, find the in-order successor
                let successor = findInOrderSuccessor(node!.right!)
                node!.value = successor.value
                node!.right = deleteNode(node!.right, successor.value)
            }
        }

        return node!
    }

    // Find the in-order successor of a node
    private func findInOrderSuccessor(_ node: Node?) -> Node? {
        var current = node!
        while current.left != nil {
            current = current.left!
        }
        return current
    }

    // Traversal functions
    // Pre-order traversal: visit node, then left, then right
    func preOrderTraverse() {
        preOrderTraverse(root)
    }

    private func preOrderTraverse(_ node: Node?) {
        if let node = node {
            print(node.value, " (Pre-order)")
            preOrderTraverse(node.left)
            preOrderTraverse(node.right)
        }
    }

    // In-order traversal: left, visit node, right
    func inOrderTraverse() {
        inOrderTraverse(root)
    }

    private func inOrderTraverse(_ node: Node?) {
        if let node = node {
            inOrderTraverse(node.left)
            print(node.value, " (In-order)")
            inOrderTraverse(node.right)
        }
    }

    // Post-order traversal: left, right, visit node
    func postOrderTraverse() {
        postOrderTraverse(root)
    }

    private func postOrderTraverse(_ node: Node?) {
        if let node = node {
            postOrderTraverse(node.left)
            postOrderTraverse(node.right)
            print(node.value, " (Post-order)")
        }
    }
}
```

### Explanation of Key Features:

1. **Node Structure**:
   - Each node contains a value and pointers to left and right children.

2. **Insertion**:
   - The `insert` function adds a new node to the correct position in the BST based on the value.

3. **Deletion**:
   - The `delete` function removes a node while maintaining BST properties. Special handling is done for nodes with two children (using the in-order successor).

4. **Traversals**:
   - **Pre-order**: Visit node, then left, then right.
   - **In-order**: Left, visit node, right.
   - **Post-order**: Left, right, visit node.

### Usage Example:
```swift
let bst = BinarySearchTree()
bst.insert(5)
bst.insert(3)
bst.insert(7)
bst.insert(1)
bst.insert(9)

print("Pre-order traversal:")
bst.preOrderTraverse()

print("\nIn-order traversal:")
bst.inOrderTraverse()

print("\nPost-order traversal:")
bst.postOrderTraverse()

bst.delete(3)
print("\nAfter deleting 3:")
bst.inOrderTraverse()
```

This implementation is efficient, with time complexity of **O(log n)** for insert and delete operations in a balanced tree, and **O(n)** in the worst case (for a skewed tree).

