```perl
use strict;
use warnings;

# Function to merge two sorted arrays into one sorted array in descending order
sub merge {
    my ($left, $right) = @_;
    my @merged;

    # Base case: if one array is empty, return the other
    return @{$left} if !@$right;
    return @{$right} if !@$left;

    # If the left array is empty, return the right array
    if (!@$left) {
        return @{$right};
    }

    # If the right array is empty, return the left array
    if (!@$right) {
        return @{$left};
    }

    # Compare elements and merge in descending order
    while ( @$left > 0 && @$right > 0 ) {
        if ( $left->[0] > $right->[0] ) {
            push @merged, $left->[0];
            shift @$left;
        } else {
            push @merged, $right->[0];
            shift @$right;
        }
    }

    # Add remaining elements from left or right
    push @merged, @$left;
    push @merged, @$right;

    return @merged;
}

# Function to perform merge sort on an array
sub merge_sort {
    my ($arr) = @_;
    return $arr if @$arr == 0;

    # Base case: if the array has only one element, return it
    return [ $arr->[0] ] if @$arr == 1;

    # Split the array into two halves
    my $mid = int(@$arr / 2);
    my $left = [ grep { $_ <= $mid } @$arr ];
    my $right = [ grep { $_ > $mid } @$arr ];

    # Recursively sort both halves
    my $sorted_left = merge_sort($left);
    my $sorted_right = merge_sort($right);

    # Merge the sorted halves
    my $merged = merge($sorted_left, $sorted_right);

    return $merged;
}

# Main program
sub main {
    print "Enter integers separated by spaces (end with 'exit'):\n";

    my @input;
    while (1) {
        my $line = <STDIN>;
        chomp($line);
        last if $line eq 'exit';

        # Split the input line into integers
        my @numbers = map { $_ = int($_) } split(/\s+/,$line);
        push @input, @numbers;

        # Check for invalid input (non-integer values)
        foreach my $num (@numbers) {
            if (!($num =~ /^\d+$/)) {
                print "Invalid input: non-integer value found.\n";
                last;
            }
        }

        # If all numbers are valid, break the loop
        last if $line eq 'exit';
    }

    # If no input was provided, exit the program
    if (!@input) {
        print "No input provided. Exiting.\n";
        return;
    }

    # Sort the array in descending order using merge sort
    my $sorted_array = merge_sort(\@input);

    # Print the sorted array
    print "Sorted array in descending order:\n";
    foreach my $num (@$sorted_array) {
        print "$num\n";
    }
}

# Run the main program
main();
```

### Explanation:

- **merge()**: Merges two sorted arrays into one sorted array in descending order.
- **merge_sort()**: Recursively splits the array into halves, sorts each half, and merges them.
- **main()**: Handles user input, validates it, and prints the sorted array.

### Edge Cases Handled:

- **Empty array**: Directly returns the array.
- **Single-element array**: Returns the single element.
- **Invalid input**: Detects non-integer values and prints an error message.
- **No input**: Exits gracefully.

